// AUTO-GENERATED by scripts/sync-help-docs.mjs — do not edit.

const helpDocsHtml = "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>gatool Help</title>\n  <style>\n    body { font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, sans-serif; margin: 0; color: #1d2733; }\n    .layout { display: grid; grid-template-columns: 260px 1fr; min-height: 100vh; }\n    nav { background: #f3f6fa; border-right: 1px solid #d5dee8; padding: 16px; position: sticky; top: 0; height: 100vh; overflow: auto; }\n    nav h1 { font-size: 1.1rem; margin: 0 0 12px; }\n    nav a { display: block; color: #1f5fa5; text-decoration: none; padding: 6px 0; font-size: 0.95rem; }\n    nav a:hover { text-decoration: underline; }\n    main { padding: 18px 24px 60px; max-width: 980px; }\n    section { margin-bottom: 40px; border-bottom: 1px solid #e4e8ee; padding-bottom: 24px; }\n    section h2 { margin-top: 0; }\n    img { max-width: 100%; height: auto; }\n    pre { overflow-x: auto; background: #f7f8fa; border: 1px solid #e0e5ec; border-radius: 6px; padding: 10px; }\n    code { background: #f7f8fa; padding: 1px 4px; border-radius: 4px; }\n    .source { margin-top: 10px; color: #516173; font-size: 0.9rem; }\n    @media (max-width: 900px) {\n      .layout { grid-template-columns: 1fr; }\n      nav { position: static; height: auto; border-right: none; border-bottom: 1px solid #d5dee8; }\n      main { padding: 14px; }\n    }\n  </style>\n</head>\n<body>\n  <div class=\"layout\">\n    <nav>\n      <h1>gatool Help</h1>\n      <a href=\"#home\">Home</a><a href=\"#install-gatool-as-an-app-full-screen\">Install gatool as an App (Full Screen)</a><a href=\"#how-do-i-use-gatool\">How do I use gatool?</a><a href=\"#setup\">Setup</a><a href=\"#match-schedule\">Match Schedule</a><a href=\"#team-data\">Team Data</a><a href=\"#announce\">Announce</a><a href=\"#play-by-play\">Play‐by‐play</a><a href=\"#alliance-selection-and-playoffs\">Alliance Selection and Playoffs</a><a href=\"#awards\">Awards</a><a href=\"#stats\">Stats</a><a href=\"#cheat-sheet\">Cheat Sheet</a><a href=\"#emcee-numbers\">Emcee numbers</a>\n    </nav>\n    <main>\n      \n      <section id=\"home\">\n        <h2>Home</h2>\n        <div class=\"content\"><p>What is gatool?<br>gatool provides FIRST® Game Announcers with up to date information while announcing events during the FIRST Robotics season. As a web-based tool, it uses up-to-date information about the event to provide a comprehensive set of useful data to Game Announcers. It is designed to work on desktops, laptops and tablet devices. In a pinch, it can be used on a mobile device.</p>\n<p>gatool is available as a <a href=\"https://www.gatool.org/\">web site</a>. You can use it without logging in, but you will need to login to access the data editing features of the tool. See the <a href=\"https://www.firstinspires.org/resource-library/frc/game-announcer\">Game Announcer Resource Page</a> for details on how to register for an account.</p>\n<p>You can review the FIRST MC and GA resources <a href=\"https://www.firstinspires.org/resource-library/frc/emcee-and-game-announcer-training-material\">here.</a></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Home\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Home</a></div>\n      </section>\n    \n\n      <section id=\"install-gatool-as-an-app-full-screen\">\n        <h2>Install gatool as an App (Full Screen)</h2>\n        <div class=\"content\"><h3>How do I make gatool full screen on my device?</h3>\n<p>In Safari on an iPad, you can save gatool to your home screen. In the address bar, tap the <strong>Share</strong> button and choose <strong>Add to Home Screen</strong>. </p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/1d31ec3f-fcbe-41c8-a831-21e555751210\" alt=\"image\"></p>\n<p>This will add an icon on your iPad&#39;s home screen, and gatool will now behave like an app. <em>NOTE: The icon may be whatever you have on the screen at the time you Add to Home Screen,</em> so you might want to have the Play by Play or Cheat Sheet screen open when you save. </p>\n<h3>Can I do the same on my desktop/laptop?</h3>\n<p>In Chrome and Safari on desktop/laptop computers, you can also save to your desktop. This will create an offline copy you can use in low bandwidth situations.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/fe4719e5-f354-4db7-9492-f8a75dbefda3\" alt=\"image\"></p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/55e9d54b-018f-4d27-b151-73f36af98b90\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Install-gatool-as-an-App-(Full-Screen)\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Install-gatool-as-an-App-(Full-Screen)</a></div>\n      </section>\n    \n\n      <section id=\"how-do-i-use-gatool\">\n        <h2>How do I use gatool?</h2>\n        <div class=\"content\"><p>gatool is organized in tabs. Each tab provides focused information to the user to help with specific aspects of a competition. The basic flow is:</p>\n<ol>\n<li>Select your event</li>\n<li>Adjust team data by interviewing teams in the pits and around the competition</li>\n<li>Upload your new team data to the gatool Cloud (on-site GAs and MCs only, please, to avoid collision)</li>\n<li>Qualification Matches<ol>\n<li>Announce teams</li>\n<li>Call play-by-play</li>\n</ol>\n</li>\n<li>Announce Alliance Selection</li>\n<li>Playoff Matches<ol>\n<li>Announce teams</li>\n<li>Call play-by-play</li>\n</ol>\n</li>\n<li>Awards</li>\n</ol>\n<p>The ultimate goal of the gatool is to reduce paper and empower Game Announcers with more relevant and more up-to-date match data.</p>\n<p>We have included a Practice Event you can use to familiarize yourself with gatool. You can select it from the Event Menu on the Setup Page. It is split into four phases:</p>\n<ul>\n<li><strong>Practice Match Phase 1</strong>: This simulates an event that is midway through Qualification matches. You will see scores for half of the Qualification matches, rankings for each team, and Alliance Selection is not ready.</li>\n<li><strong>Practice Match Phase 2</strong>: This simulates an event that is half complete. You will see scores for all of the Qualification matches, rankings for each team, and Alliance Selection is ready. You can therefore try using our Alliance Selection tool on the Alliance Selection Screen.</li>\n<li><strong>Practice Match Phase 3</strong>: This simulates an event that is half way through Playoffs. You will see scores for half of the Playoff matches, and the Playff Bracket shows results for the completed matches as well as teams assigned to future matches.</li>\n<li><strong>Practice Match Phase 4</strong>: This simulates an event that is complete. You will see scores for all of the Playoff matches, and the Playoff Bracket is completely filled.</li>\n</ul>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/ee89d13f-e33d-4335-a6e2-3a24d6b5965b\" alt=\"image\"></p>\n<p><a href=\"https://www.youtube.com/watch?v=YNqy7gKGzFU\">If you are disinclined to read the documentation contained in this site, we&#39;ve got an in-depth training video you can watch on YouTube.</a></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/How-do-I-use-gatool?\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/How-do-I-use-gatool?</a></div>\n      </section>\n    \n\n      <section id=\"setup\">\n        <h2>Setup</h2>\n        <div class=\"content\"><p>The Setup tab is where you select your event. Choose a year, then the event. You can filter the event list by timeframe or by event type, such as Regional or a specific District. You can type the name as well.</p>\n<p>The screen will display status information about the data that are available for the event. These data are read directly from <em><strong>FIRST</strong></em>, and they are updated throughout the competition by the Field Management System. As the event progresses, more data will be available and the status indicators will change.</p>\n<p>While event data load, the tabs at the top of the screen will change color. For instance, when a match schedule for the event is available, <strong>the Match Schedule</strong> tab will turn green. This is your clue that the match schedule is loaded and you are ready to go to work. Similarly, the <strong>Teams, Ranks</strong> and <strong>Awards</strong> tabs will turn green once the team list and rankings data become available, and <strong>Alliance Selection</strong> will turn green once Qualification matches complete.</p>\n<p>Once you complete Alliance Selection, return to this page to load the Playoff schedule by tapping or clicking the <strong>&quot;Tap to refresh Schedule&quot;</strong> button. The Playoff schedule changes as a result of match play and advancement criteria during Playoff stages, and updates will load automatically as the competition progresses. </p>\n<p>You can change whether and how gatool displays certain information in other screens. Adjust the switches to configure gatool to your specific tastes. You can make adjustments during an event, too. For instance, it is common to disable Sponsors on Announce once all teams have been introduced for the first time.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/fd7b512a-2325-4bb5-923f-687e01591464\" alt=\"image\"></p>\n<p>On the right hand side are the commonly used configuration options. Here is a summary of how each option works:</p>\n<ul>\n<li><strong>Show Sponsors on Announce</strong>: when enabled, team Sponsors will appear on the Announce Screen. The default setting is enabled.</li>\n<li><strong>Show Awards on Announce</strong>: when enabled, team awards will appear on the Announce Screen. The default setting is enabled.</li>\n<li><strong>Show Notes on Announce &amp; Play-By-Play</strong>: when enabled, team notes will appear on the Announce and Play-By-Play Screens. The default setting is enabled.</li>\n<li><strong>Show Mottoes on Announce &amp; Play-By-Play</strong>: when enabled, team mottoes will appear on the Announce and Play-By-Play Screens. The default setting is enabled.</li>\n<li><strong>Show Champs Statistice on Announce in World and District Champs</strong>: when enabled, a team&#39;s lifetime statistics at World or District Champs will appear Announce Screen. The default setting is disabled.</li>\n<li><strong>Show Quals Statistics on Play-By-Play during Quals</strong>: when enabled, each team&#39;s Qualification performance stats will show on the Play-By-Play Screen when viewing a Qualification match. The default setting is enabled.</li>\n<li><strong>Show Quals Statistics on Play-By-Play during Playoffs</strong>: when enabled, each team&#39;s Qualification performance stats will show on the Play-By-Play Screen when viewing a Playoff match. The default setting is disabled.</li>\n<li><strong>Swap Play-By-Play Screen Orientation</strong>: when enabled, the Red and Blue Alliances will switch positions on the Play-By-Play Screen. This is to support games where the action occurs on the side of the field oppposite from the drivers&#39; stations. The default setting is disabled.</li>\n<li><strong>Swap Emcee Screen Orientation</strong>: when enabled, the Red and Blue alliance hints will switch positions on the Emcee screen. This is to help the emcee more easily identify which team has the advantage in a playoff match. The default setting is disabled.</li>\n<li><strong>Automatically advance to the next match when loading the event</strong>: when enabled, gatool will read the completed matches from FMS and set your current match to the latest uncompleted match. The default setting is disabled.</li>\n<li><strong>For how many years should we display awards on the Announce Screen?</strong>: this menu sets the number of lookback years to include in our list of awards for each team. The default choice is three.</li>\n<li><strong>How many months before we consider a team&#39;s data to be stale?</strong>: this menu sets the number of months after which we consider a team&#39;s community-sourced updates to be stale. You can verify and update each team&#39;s specific details on the Team Data screen. The default choice is six months.</li>\n<li><strong>Enable Test Match Mode</strong>: when enabled, gatool will not use a schedule to determine which teams play in any given match. The Game Announcer can choose which teams will play directly on the Announce or Play-By-Play screens. This mode is to facilitate scenarios when you cannot connect to the Internet during an event, or for supporting Playoffs during offline events in the offseason. The default setting is disabled.</li>\n<li><strong>Set your time format</strong>: this menu sets the format for time display in the app. The default choice is 12 hr, which will include am and pm when displaying time.</li>\n<li><strong>Logout</strong>: use this button to log out of gatool. When you logout, your local changes will persist, so you can login later and your team data will still be here.</li>\n</ul>\n<p>At the bottom of the screen, there are two boxes with additional options, organized by function: <strong>Advanced Event Settings</strong> and <strong>Team Data Updates</strong>.</p>\n<ul>\n<li><strong>Advanced Event Settings.</strong> These two menus adjust the flow of the playoffs in unusual scenarios. The first option sets the number of non-competing teams that may be included in your team list. This is a rare condition, but if it happens at your event, choose the number of teams that are on the team list that are not competing. The default choice is zero.</li>\n<li><strong>Update Team Data</strong> Use this to fetch updated community-sourced team data from gatool Cloud. gatool automatically loads communuty-sourced team data when you select an event, but if you are working with a partner and you are each entering data into gatool, you can each update half of the teams. When you are both done, you can then load each other&#39;s changes. NOTE: If you have unsaved local changes to team data, you will see a notice here asking whether you want to upload those changes to gatool Cloud. You can also discard those local changes.</li>\n</ul>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/f41b0c5a-2fd8-47d7-ba1f-045e537ba2c6\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Setup\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Setup</a></div>\n      </section>\n    \n\n      <section id=\"match-schedule\">\n        <h2>Match Schedule</h2>\n        <div class=\"content\"><p>The Match Schedule tab displays the match schedule data. This is up-to-date data from <em><strong>FIRST</strong></em>. You can always re-load the schedule from the Setup page. The Match Schedule is read only, and it will exapnd to include Playoff matches once they become available. The Match Schedule also shows match results as they become available. Red highlight indicates a Red Alliance win; Blue highlight indicates a Blue Alliance win; and Green highlight indicates a tie. On the left hand side of the table, it also shows predicted and actual match times to help you understand how close to on schedule your event is running.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/e2b2191c-15f1-45a0-baab-a3b3324be635\" alt=\"image\"></p>\n<p>If you need to use gatool at an event that is not connected to the Internet, you can get a schedule report from your Scorekeeper as Excel and upload it here. For more details about the Offline event, see this short video. For playoffs, you&#39;ll need to load the initial Playoff schedule from your Scorekeeper and then reload as the rounds complete. Alternatively, you can use Test Match mode for playoffs.</p>\n<p><a href=\"https://youtu.be/RDsRCnChaJY\">This video explains how to upload a schedule for offline use</a></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Match-Schedule\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Match-Schedule</a></div>\n      </section>\n    \n\n      <section id=\"team-data\">\n        <h2>Team Data</h2>\n        <div class=\"content\"><p>The Team Data tab displays information about the teams that are registered for the event. The table displays the current data from <em><strong>FIRST</strong></em>, but it allows you to modify what you see in the Announce and Play-by-play screens.</p>\n<p>You can also dowmload a spreadsheet containing the team details and schedule (when available). Tap on the link at the top of the table to download the team data and schedule. You can merge this with Word to create team data sheets you can hand out at an event. <a href=\"http://gatool.org/images/gatool_team_information_sheets.docx\">Tap here to download the merge document (docx)</a>. Note, the merge doc contains conditional merge tags. Do not edit the merged fields, as they will no longer work properly. Feel free to edit any other portion of the document.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/3108a01f-d5bc-4f1d-8531-5c35f87e52d5\" alt=\"image\"></p>\n<p>Tap on a team number to open its details page. Edit any of the data in the form and tap <strong>Done</strong> to save the changes. These changes will appear in the <strong>Team Data</strong>, so if you want to revert any change to the <em><strong>FIRST</strong></em> data, simple clear the field in the details page and tap <strong>Done</strong>. If you want to erase ALL changes and revert to the data supplied by <em><strong>FIRST</strong></em>, reset the local storage from the Setup Screen.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/a6d9463b-367f-4054-9c4b-64810b000367\" alt=\"image\"></p>\n<p>When you make changes to a team&#39;s data, gatool records that as a &quot;visit&quot; to the team. Last visit times appear nder the team number, and the team number button will turn green if you have recorded a visit to a team. This can be very helpful as you work the pits. You must tap <strong>Done</strong> or <strong>Save Team Data to gatool Cloud</strong> to record a visit. Note that if you exit a Team Details page without recording a visit, no changes will be saved. You can reset all visit times by tapping on the <strong>Reset all visit times</strong> button at the bottom of the table.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/000f3c47-c653-4bcf-8d06-536936bbdd7b\" alt=\"image\"></p>\n<p>The Team Table is sortable. Tap on any column head to sort by that column. Once sorted, tapping again will reverse the sort order of that column.</p>\n<p>It is a best practice not to adjust the Awards field for a specific team. If you do, new Awards will not accrue to the teams whose Awards you edit. Instead, use the Awards controls on the Setup page. You can clear out all of the changes you have made to Awards, leaving all other changes intact, by tapping on the <strong>Reset stored awards</strong> button at the bottom of the Team Data screen. Note: it is a best practice to reset awards at the start of an event.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/9b3ff50c-0c0c-44c7-9d1e-9c77107804df\" alt=\"image\"></p>\n<p>Any updated information is stored in the browser&#39;s local storage, so it should persist even if you close the browser or switch events. You can load crowd sourced team data by tapping on the <strong>Load Event Data from the gatool Cloud</strong> button on the Setup Screen.</p>\n<p>If you are a GA or MC at an event, please confer with your GA or MC partner, update your local team data, and then save it to the gatool Cloud.  You can save to the gatool Cloud by tapping <strong>Save Event Data to the gatool Cloud</strong> on the Setup Screen. Once you have saved, you can load the data on another device so that all of your devices are synced. <em><strong>We ask that only the on-site GA or MC save to gatool cloud during an event.</strong></em></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Team-Data\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Team-Data</a></div>\n      </section>\n    \n\n      <section id=\"announce\">\n        <h2>Announce</h2>\n        <div class=\"content\"><p>Once you have interviewed the teams and have updated their robot names and sponsors (and other items, of course!) in your gatool, you are ready to announce. There are two screens for match announcing: <strong>Announce</strong> and <strong>Play-by-play.</strong> </p>\n<p>The <strong>Announce Screen</strong> is organized to make it easy for you and your emcee to announce the teams before a match. The screen presents the teams in announce order, so you should be able to read from top to bottom. The current match is indicated at the top and bottom of the screen. Also, there are buttons to cycle through the matches. You can use these buttons to preview upcoming matches or to review previous matches. Each time you tap the <strong>Next Match</strong> or <strong>Previous Match</strong> buttons, a call is made to retrieve current ranking data. It is best to retrieve current ranking data right before your current match to fetch the latest results from <em><strong>FIRST</strong></em>. </p>\n<p>The Announce screen includes a lot of information about the teams, including:</p>\n<ul>\n<li>Team number</li>\n<li>Rookie year</li>\n<li>Team Name</li>\n<li>Hometown</li>\n<li>Robot name</li>\n<li>Organization or school</li>\n<li>Sponsors</li>\n<li>Awards</li>\n<li>Current event ranking</li>\n</ul>\n<p>Ranking is color coded to help build excitement. The number 1 alliance is highlighted in gold. Numbers 2 through 8 are highlighted in green. Numbers 9 and 10 are highlighted in yellow.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/90d5d648-e2fb-4d7a-bb68-1347ff4f827c\" alt=\"image\"></p>\n<h2>Playoff features</h2>\n<p>During the Playoffs, you might need to substitute or rearrange teams in their stations. To replace a team, simply <strong>tap on a team number</strong>. Enter the replacement team number and tap <strong>Make it so</strong>. The Announce and Play-by-play screens will now show data for the replacement team. The update will not affect other gatool users, nor will it update FMS. FMS will publish the match results with the substitutions after the match completes.</p>\n<p>You will not be allowed to substitute a team that does not appear in the event. </p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/c382124f-065d-4305-9083-9f6198ba03af\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Announce\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Announce</a></div>\n      </section>\n    \n\n      <section id=\"play-by-play\">\n        <h2>Play‐by‐play</h2>\n        <div class=\"content\"><p>The Play-by-play screen is organized to make it easy for you to provide colorful and relevant commentary during a match. The screen presents the teams from the perspective of the scoring table, with Blue Alliance on the left and Red Alliance on the right. The current match is indicated at the top of the screen. The tournament high score to date is indicated at the bottom of the screen. <strong>Note:</strong> The high score indicator is also a button that refreshes the current standings. </p>\n<p>At the top and bottom of the screen, there are buttons to cycle through the matches. You can use these buttons to preview upcoming matches or to review previous matches. Each time you tap the Next Match or Previous Match buttons, a call is made to retrieve current ranking data. It is best to refresh current match data right before your current match to ensure that you have the the latest results from FMS. </p>\n<p>The Announce screen includes a reduced set of information about the teams, including:</p>\n<ul>\n<li>Team number</li>\n<li>Team Name</li>\n<li>Hometown</li>\n<li>Robot name</li>\n<li>Organization or school</li>\n<li>Current event ranking</li>\n<li>Qualification average</li>\n<li>Win-loss-tie record</li>\n</ul>\n<p>Ranking is color coded to help build excitement and it follows the scheme from the Announce screen.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/e4b049f9-6225-416e-ac4d-9124e848c5f6\" alt=\"image\"></p>\n<p>At the top center of the screen, there is a match timer. This is a handy tool to help you identify the time remaining in the match and what phase of the match is currently active. Tap it once to start the timer, and tap it at any time to reset the timer. The phases of the timer include:</p>\n<p><strong>Autonomous.</strong> During the Autonomous period, the timer is orange and counts down to the end of Autonomous period.</p>\n<p><strong>Teleoperated.</strong> During the Teleoperated period, the timer is green and counts down to the Endgame, which begins when 30 seconds remain in the match.</p>\n<p><strong>Endgame.</strong> During the Endgame, the timer is red. When 10 seconds remain in the match, it will cycle alternatingly red and white until time expires.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/a316edb7-c82b-46dd-adaf-f2035ebc63aa\" alt=\"image\"></p>\n<h3>Playoff features</h3>\n<p>During the Playoffs, you might need to substitute or rearrange teams in their stations. To replace a team, simply <strong>tap on a team number</strong>. Enter the replacement team number and tap <strong>Make it so</strong>. The Announce and Play-by-play screens will now show data for the replacement team. The update will not affect other gatool users, nor will it update FMS. FMS will publish the match results with the substitutions after the match completes.</p>\n<p>You will not be allowed to substitute a team that does not appear in the event. </p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/66bd6872-b093-40ac-98ce-7213eaf2c966\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Play‐by‐play\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Play‐by‐play</a></div>\n      </section>\n    \n\n      <section id=\"alliance-selection-and-playoffs\">\n        <h2>Alliance Selection and Playoffs</h2>\n        <div class=\"content\"><p>The Alliance Selection Screen is designed to help you and your emcee inform and entertain during Alliance Selection. Often the most confusing part of any <em><strong>FIRST</strong></em> event, Alliance Selection is a critical component of the <em><strong>FIRST</strong></em> competition philosophy. In many venues, there is no clear view of the scoring screen, which can impede teams when making their Alliance partner choices. Also, it is difficult for a Game Announcer to search through a long list of teams in order to call out their names, schools and home towns after their number is called by the Alliance Captain.</p>\n<p>The Alliance Selection Screen uses a &quot;tap on the team&quot; interface to help ease the stress of Alliance Selection, and it is intended to be used by both emcees and Game Announcers. To ensure that you have the latest ranking data, tap on the high score on the Play-by-play Screen or by cycle backward and forward on the Announce or Play-by-play Screens. </p>\n<p>There is a status indicator that lets you know whether gatool believes it has the final rankings in order to proceed with Alliance Selection. Please be sure to review the rankings with your Scorekeeper before proceeding with Alliance Selection.</p>\n<p>All team numbers on the screen are active, so that when you tap them, you will have options based on whether the team is available for selection. As teams accept their invitations, the screen will adjust to reflect the decisions. If you make a mistake, you can always undo the choice.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/d01d3271-5f7e-435b-9174-80ceb40182a6\" alt=\"image\"></p>\n<p>Alliance Captains are organized according to the ranking at the completion of Qualification play, and the Alliance Captains are pre-populated in their Alliances. The Alliances are on the right hand side of the screen. The current Alliance pick is also highlighted with a red border. Before Alliance Selection begins, it is customary to introduce the Alliance Captains. Tap on their team number to reveal their team particulars, then choose <strong>Alliance Captain Announce</strong> to dismiss the dialog.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/b6942abc-50c5-43ca-a5ef-8b98c60353df\" alt=\"image\"></p>\n<p>To make a selection, tap on a team number. A modal dialog will appear that displays the team number, name, hometown and organization. This is to help the Game Announcer provide details about the team as they come onto the field to accept of decline the offer to join the Alliance. If the accept the offer, tap <strong>Gratefully Accept</strong>. If they decline the offer, tap <strong>Respectfully Decline</strong>.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/43647235-32e1-4795-8b30-21c7eb40f69e\" alt=\"image\"></p>\n<p>When a team accepts an offer, the folowing actions occur: they will be committed to the highlighted Alliance position, the team will be removed from the list of available teams, and the highlighted Alliance choice will advance to the next choice. If the invited team is in the top 8 of the remaining teams, they will move out of the green and pink boxes and move to the Alliance box. If they decline the offer, then select another team. If you make a mistake, you can undo the choice, all the way back to the beginning.</p>\n<p>Alliance Captains who have not yet chosen their first Alliance partner are also eligible for Alliance selection. If you tap an Alliance Captain, announce their particulars and choose <strong>Gratefully Accept</strong> or <strong>Respectfully Decline</strong>. If they accept, their team will move to the highlighted Alliance choice, and all of the Captains below their rank will advance one slot. In addition, a new number 8 Captain will come out of the available alliance pool according to the qualification rankings. A new team will flow into the bottom of the green box, according to the qualification rankings.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/070111f5-c16e-4cb6-8efd-ccd35aa0c723\" alt=\"image\"></p>\n<p>There is a special Championship case, in which Alliances contain 4 teams and there are no reserves. gatool understands this situation and will display a third choice for each Alliance. Since there are no backups in this situation, there is no Backup Alliance box in Championship Alliance Selection.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/b6da3fe3-9ac2-4886-9ae7-653426d0cab8\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Alliance-Selection-and-Playoffs\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Alliance-Selection-and-Playoffs</a></div>\n      </section>\n    \n\n      <section id=\"awards\">\n        <h2>Awards</h2>\n        <div class=\"content\"><p>The Awards Screen makes it easy to announce details about award winners during a competition. When you tap on a team number, a modal dialog will display the Team details. Announce the team then tap Congratulations! The teams remain in the list, so teams who receive multiple awards can be announced.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/6c7e65fe-7a3f-4fa8-9997-b1ae614885ed\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Awards\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Awards</a></div>\n      </section>\n    \n\n      <section id=\"stats\">\n        <h2>Stats</h2>\n        <div class=\"content\"><p>gatool keeps track of event and world high scores. These scores can be used to raise excitement when a match sets a new event high score of bests an existing world high score. World high scores are indicated in the red box, and event high scores are indicated in the blue box.<br><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/695fa0be-de4e-4b02-83ce-3c577a1d19fe\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Stats\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Stats</a></div>\n      </section>\n    \n\n      <section id=\"cheat-sheet\">\n        <h2>Cheat Sheet</h2>\n        <div class=\"content\"><p>We have prepared a Cheat Sheet that summarizes timing, scoring, field elements and game play. We&#39;ve included it here as a resource. If you are working from the Scoring Table, then the Cheat Sheet will match your view of the Playing Field.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/dccafed9-6e21-49c2-87cf-03b2f9d23ae0\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Cheat-Sheet\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Cheat-Sheet</a></div>\n      </section>\n    \n\n      <section id=\"emcee-numbers\">\n        <h2>Emcee numbers</h2>\n        <div class=\"content\"><p>gatool offers a large number for the current match to help your emcee when they are building excitement for the current match. In Playoffs, it also shows which alliances are playing and what color has the advantage when heading into the second match of a playoff series.</p>\n<p>During Qualification matches, the Emcee #s tab will display the current match, as selected in the Announce tab.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/eb950d00-0664-487c-85d2-fe7f6e6e4e04\" alt=\"image\"></p>\n<p>During Playoff matches, the Emcee #s tab will display the current match along with the alliance pairings. In the second match of a seriec, the match number will be the color of the alliance who will advance if they win the match.</p>\n<p><img src=\"https://github.com/arthurlockman/gatool-ui/assets/158981/51a6674c-50ab-466e-ae9f-3432750ef016\" alt=\"image\"></p>\n</div>\n        <div class=\"source\">Source: <a href=\"https://github.com/arthurlockman/gatool-ui/wiki/Emcee-numbers\" target=\"_blank\" rel=\"noopener noreferrer\">https://github.com/arthurlockman/gatool-ui/wiki/Emcee-numbers</a></div>\n      </section>\n    \n    </main>\n  </div>\n</body>\n</html>";
export default helpDocsHtml;
